    int n = weight.length;
    int count = 0;
    int i = 0;
    while (i < n) {
        int j = i;
        long max = weight[i];
        while (j < n && weight[j] >= max) {
            max = Math.max(max, weight[j]);
            j++;
        }
        if (j > i && j < n && weight[j] < max) {
            count++;
            i = j + 1;
        } else {
            i++;
        }
    }
    return count;
}
