public static long solve(long[] weight) {
    int n = weight.length;
    int count = 0;
    int i = 0;

    while (i < n) {
        int j = i;
        long max = weight[i];
        // Find the largest possible segment starting at i
        while (j < n) {
            max = Math.max(max, weight[j]);
            if (weight[j] < max) {
                // Found a potential segment, try to extend as much as possible
                int k = j + 1;
                long currentMax = max;
                while (k < n) {
                    currentMax = Math.max(currentMax, weight[k]);
                    if (weight[k] < currentMax) {
                        j = k;
                        max = currentMax;
                    }
                    k++;
                }
                count++;
                i = j + 1;
                break;
            }
            j++;
        }
        if (j >= n) {
            break;
        }
    }

    return count;
}
